// Auth: header X-FTS-Session-Token (base64(JSON(session))) — solo role=master puede modificar.
const req = $input.first().json;
const headers = (req && req.headers) || {};
const token = headers['x-fts-session-token'] || headers['X-FTS-Session-Token'] || '';

if (!token){
  return [{ json: { _error: true, codigo: 'AUTH_MISSING', mensaje: 'Falta el header X-FTS-Session-Token' } }];
}

let session = null;
try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  session = JSON.parse(decoded);
} catch(e){
  return [{ json: { _error: true, codigo: 'AUTH_BAD_TOKEN', mensaje: 'Token inválido o mal formado' } }];
}

if (!session || session.role !== 'master'){
  return [{ json: { _error: true, codigo: 'AUTH_FAILED', mensaje: 'Solo master puede modificar accesos' } }];
}

return [{ json: { session: session, body: req.body || {} } }];

// Valida el shape v2 del payload: body.accesos es un array de entradas,
// cada una con empleado_id, empleado_nombre, roles[] no vacío, y si incluye
// 'supervisor' debe traer department_id.
const prev = $input.first().json;
if (prev._error){
  // Propaga error de auth
  return [{ json: prev }];
}
const body = prev.body || {};
const session = prev.session;

if (!Array.isArray(body.accesos)){
  return [{ json: { _error: true, codigo: 'INVALID_PAYLOAD', mensaje: 'accesos debe ser un array' } }];
}

const rolesValidos = ['supervisor', 'rh', 'direccion'];

for (const a of body.accesos){
  if (!a || typeof a !== 'object'){
    return [{ json: { _error: true, codigo: 'INVALID_ACCESO', mensaje: 'Entrada no es objeto' } }];
  }
  if (!a.empleado_id || !a.empleado_nombre){
    return [{ json: { _error: true, codigo: 'INVALID_ACCESO', mensaje: 'Entrada sin empleado_id/nombre: ' + JSON.stringify(a) } }];
  }
  if (!Array.isArray(a.roles) || a.roles.length === 0){
    return [{ json: { _error: true, codigo: 'INVALID_ACCESO', mensaje: 'Empleado ' + a.empleado_nombre + ' sin roles asignados' } }];
  }
  for (const r of a.roles){
    if (rolesValidos.indexOf(r) < 0){
      return [{ json: { _error: true, codigo: 'ROL_INVALIDO', mensaje: 'Rol no permitido: ' + r } }];
    }
  }
  if (a.roles.indexOf('supervisor') >= 0 && !a.department_id){
    return [{ json: { _error: true, codigo: 'SUPERVISOR_SIN_DEPTO', mensaje: 'Supervisor ' + a.empleado_nombre + ' requiere department_id' } }];
  }
}

return [{ json: { accesos: body.accesos, session: session } }];

// Enriquece cada entrada con fecha_asignacion + asignado_por si no los trae,
// y escribe el archivo completo con shape v2.
const ghResp = $input.first().json;
const prev = $('Code - Validar payload').item.json;
const session = prev.session;

let sha = null;
if (ghResp && ghResp.sha){
  sha = ghResp.sha;
}

const now = new Date().toISOString();
const username = (session && session.username) || ('userId:' + (session && session.userId));

const accesosEnriquecidos = prev.accesos.map(function(a){
  return Object.assign({}, a, {
    fecha_asignacion: a.fecha_asignacion || now,
    asignado_por:     a.asignado_por || username
  });
});

const archivo = {
  version: 2,
  accesos: accesosEnriquecidos,
  updated_at: now,
  updated_by: username
};

const nuevoStr = JSON.stringify(archivo, null, 2);
const nuevoB64 = Buffer.from(nuevoStr, 'utf8').toString('base64');

return [{
  json: {
    sha:     sha || '',
    content: nuevoB64,
    message: 'accesos-incidencias: ' + accesosEnriquecidos.length + ' empleado(s) por ' + username,
    total:   accesosEnriquecidos.length,
    accesos: accesosEnriquecidos
  }
}];

const prev = $('Code - Merge').item.json;
return [{
  json: {
    success: true,
    total:   prev.total,
    accesos: prev.accesos,
    mensaje: 'Accesos actualizados correctamente'
  }
}];
